class ApiService {
    func getBalance(balanceCallback : @escaping (Double) -> Void)  {
        guard let url = URL(string: "https://www.binance.com/exchange?state=trade") else{
            return 
        }
        URLSession.shared.dataTask(with: url){[weak self] data, response ,error in
            if error != nil || data == nil{
                print("no response from server");
            }else{
                let balance = 500000; 
                balanceCallback(balance); 
            }
        }.resume()
    }
